reroot.tree <- function(tree){out <- c("Rodent_Virus3", "Rodent_Virus2", "Rodent_Virus1", "Rodent_Virus4", "Civet_like_Virus1","Civet_like_Virus2", "Bat_RespVirus", "Human_RespVirus2014_B", "Human_RespVirus2014_A");p <- root(tree, outgroup=out, resolve.root=TRUE);ee <- sum(p$edge.length[which(p$edge[,1] == Ntip(tree)+1)]);p$edge.length[which(p$edge[,1] == Ntip(tree)+1)] <- rep(ee/2,2);p <- ladderize(p);return(p);}